// Extract ID and Normalize Input
// Also detect if this came from Force Webhook (single ticket mode)
// Pass through audit_type, last_response_count, previous_context for live audit
const input = items[0].json.body || items[0].json;
let id = input.ticket_id;
if(!id && input.raw_json && input.raw_json.ticket_id) id = input.raw_json.ticket_id;
if(!id && typeof input.raw_json === 'string') { try { id = JSON.parse(input.raw_json).ticket_id; } catch(e){} }

// Check if this came from Force Webhook (has body.ticket_id or force flag)
const isSingleTicket = !!(input.ticket_id || input.force);

// Live audit fields from get-pending
const auditType = input.audit_type || 'full';
const lastResponseCount = input.last_response_count || 0;
const previousContext = input.previous_context || null;

return { json: { target_id: id, is_single_ticket: isSingleTicket, audit_type: auditType, last_response_count: lastResponseCount, previous_context: previousContext } };

const ticket = items[0].json.ticket || {};
const responses = items[0].json.responses || [];

// Get live audit context from Extract ID node
const auditType = $('Extract ID').item.json.audit_type || 'full';
const lastResponseCount = $('Extract ID').item.json.last_response_count || 0;
const previousContext = $('Extract ID').item.json.previous_context || null;

// Determine which responses to include
const isIncremental = (auditType === 'incremental' && previousContext);
const startIdx = isIncremental ? lastResponseCount : 0;

// Build transcript header
let transcript = `### TICKET ${ticket.id}\nTITLE: ${ticket.title}\nSTATUS: ${ticket.status}\nCREATED: ${ticket.created_at || 'N/A'}\nAUDIT TYPE: ${auditType}\n\n`;

// For incremental audits, prepend previous audit context
if (isIncremental) {
  transcript += `### PREVIOUS AUDIT CONTEXT\n`;
  transcript += `Score: ${previousContext.overall_score}, Sentiment: ${previousContext.overall_sentiment}\n`;
  transcript += `Summary: ${previousContext.executive_summary}\n`;
  transcript += `Agent Scores: ${JSON.stringify(previousContext.agent_scores)}\n`;
  transcript += `Problems Found: ${(previousContext.problems_found || []).join(', ')}\n`;
  transcript += `Responses Already Audited: ${previousContext.audited_response_count || lastResponseCount}\n\n`;
  transcript += `### NEW RESPONSES (evaluate only these, considering previous context)\n\n`;
}

// Track agent responses for shift checking
const agentChecks = [];
let previousCustomerMessageTime = ticket.created_at || null;

responses.forEach((r, idx) => {
  const person = r.person || {};
  const personType = person.person_type || r.type || 'system';
  const name = person.full_name || person.first_name || (person.last_name ? (person.first_name || '') + ' ' + person.last_name : '') || person.name || 'System';
  const email = person.email || '';
  const text = r.content ? r.content.replace(/<[^>]*>/g, '') : '';
  const timestamp = r.created_at || r.created || r.timestamp || '';

  // For incremental: only include responses after lastResponseCount
  if (idx >= startIdx) {
    transcript += `[${personType.toUpperCase()}] ${name}${email ? ' (' + email + ')' : ''} [${timestamp}]: ${text}\n`;
  }

  // Track agent responses for shift checking (only new ones for incremental)
  if (personType === 'agent' && email && timestamp && idx >= startIdx) {
    agentChecks.push({
      agent_email: email,
      agent_name: name,
      datetime: timestamp,
      response_index: idx,
      response_type: 'agent_response',
      customer_message_time: previousCustomerMessageTime
    });
  }

  if (personType === 'customer' && timestamp) {
    previousCustomerMessageTime = timestamp;
  }

  if ((personType === 'system' || !personType) && text && timestamp && idx >= startIdx) {
    const assignedMatch = text.match(/assigned.*?to\s+([^\s<]+@[^\s>]+)/i) || 
                         text.match(/assigned.*?to\s+([A-Za-z\s]+)/i);
    if (assignedMatch && timestamp) {
      const assignedAgent = assignedMatch[1].trim();
      agentChecks.push({
        agent_email: assignedAgent.includes('@') ? assignedAgent : null,
        agent_name: assignedAgent,
        datetime: timestamp,
        response_index: idx,
        response_type: 'ticket_assignment',
        assignment_text: text
      });
    }
  }
});

return { 
  json: { 
    ticket_id: ticket.id, 
    clean_transcript: transcript,
    ticket_created_at: ticket.created_at,
    agent_checks: agentChecks,
    raw_responses: responses,
    audit_type: auditType,
    last_response_count: lastResponseCount,
    is_incremental: isIncremental
  } 
};

// Get data from previous nodes
// Note: This node receives data from both "Get System Message" and "Check Agent Shifts"
// We need to identify which input is which
const inputItems = items || [];

let transcriptData = null;
let shiftResults = [];
let systemMessage = '';

// Process all input items to find the right data
inputItems.forEach(item => {
  const json = item.json || {};

  // Check if this is from "Get System Message" (has system_message property)
  if (json.system_message !== undefined) {
    systemMessage = json.system_message || '';
  }

  // Check if this is from "Check Agent Shifts" (has results array)
  if (json.results !== undefined && Array.isArray(json.results)) {
    shiftResults = json.results || [];
  }

  // Check if this is from "Build Transcript" (has ticket_id and agent_checks)
  if (json.ticket_id && json.agent_checks !== undefined) {
    transcriptData = json;
  }
});

// Fallback: if we don't have transcriptData from input, get it from node reference
if (!transcriptData) {
  try {
    transcriptData = $('Build Transcript').item.json;
  } catch(e) {
    console.error('Could not get transcript data:', e);
  }
}

// Fallback: if we don't have shiftResults, get from node reference
if (shiftResults.length === 0) {
  try {
    const shiftData = $('Check Agent Shifts').item.json;
    shiftResults = shiftData.results || [];
  } catch(e) {
    console.error('Could not get shift results:', e);
  }
}

// Fallback: if we don't have systemMessage, get from node reference
if (!systemMessage) {
  try {
    const sysMsgData = $('Get System Message').item.json;
    systemMessage = sysMsgData.system_message || '';
  } catch(e) {
    console.error('Could not get system message:', e);
  }
}

if (!transcriptData) {
  throw new Error('Missing transcript data');
}

// Create a map for quick lookup: agent_email_datetime -> shift result
const shiftMap = {};
shiftResults.forEach(result => {
  const key = `${result.agent_email}_${result.datetime}`;
  shiftMap[key] = result;
});

// Enrich agent_checks with shift data
const enrichedChecks = (transcriptData.agent_checks || []).map(check => {
  if (!check.agent_email || !check.datetime) {
    return { ...check, shift_check: null };
  }

  const key = `${check.agent_email}_${check.datetime}`;
  const shiftData = shiftMap[key] || null;

  return {
    ...check,
    shift_check: shiftData ? {
      was_on_shift: shiftData.was_on_shift,
      is_weekend: shiftData.is_weekend,
      day_of_week: shiftData.day_of_week,
      shift_type: shiftData.shift_info?.shift_type || null,
      shift_start: shiftData.shift_info?.shift_start || null,
      shift_end: shiftData.shift_info?.shift_end || null
    } : null
  };
});

// Build shift context summary for AI prompt
let shiftContextSummary = "\n### 📅 SHIFT CONTEXT FOR DELAY ANALYSIS\n";
shiftContextSummary += "Use this data to determine if response delays should be penalized:\n\n";

if (enrichedChecks.length > 0) {
  enrichedChecks.forEach((check, idx) => {
    if (check.shift_check && check.agent_email) {
      const sc = check.shift_check;
      shiftContextSummary += `\n**${idx + 1}. Agent: ${check.agent_name || check.agent_email}**\n`;
      shiftContextSummary += `   - Action: ${check.response_type === 'agent_response' ? 'Response' : 'Ticket Assignment'}\n`;
      shiftContextSummary += `   - Time: ${check.datetime}\n`;
      shiftContextSummary += `   - Was On Shift: ${sc.was_on_shift ? '✅ YES' : '❌ NO'}\n`;
      shiftContextSummary += `   - Weekend: ${sc.is_weekend ? '✅ YES' : '❌ NO'}\n`;
      shiftContextSummary += `   - Day: ${sc.day_of_week}\n`;
      if (sc.shift_type) {
        shiftContextSummary += `   - Shift Type: ${sc.shift_type}\n`;
      }
      if (check.customer_message_time) {
        shiftContextSummary += `   - Customer Message Time: ${check.customer_message_time}\n`;
      }
    }
  });
} else {
  shiftContextSummary += "⚠️ No agent shift data available. Assume agents were ON SHIFT when evaluating delays.\n";
}

// Prepare system message by replacing placeholders
let preparedSystemMessage = systemMessage || '';
if (preparedSystemMessage) {
  // Replace transcript placeholder
  if (transcriptData.clean_transcript) {
    preparedSystemMessage = preparedSystemMessage.replace(/\{\{ \$json\.clean_transcript_json_safe \}\}/g, transcriptData.clean_transcript);
  }

  // Replace shift context placeholder
  preparedSystemMessage = preparedSystemMessage.replace(/\{\{ \$json\.shift_context \}\}/g, shiftContextSummary);
}

// For incremental audits, prepend incremental mode instructions
const isIncremental = transcriptData.is_incremental || false;
const auditType = transcriptData.audit_type || 'full';
if (isIncremental && preparedSystemMessage) {
  const incrementalPrefix = `INCREMENTAL AUDIT MODE: You are continuing an audit of an ongoing ticket (ticket is still OPEN, not closed yet).\n` +
    `The PREVIOUS AUDIT CONTEXT in the transcript shows scores and findings from earlier responses that have already been audited.\n` +
    `Evaluate ONLY the NEW RESPONSES below. Return updated scores considering both the previous context and new information.\n` +
    `If new responses change your assessment of the overall ticket quality, adjust scores accordingly.\n` +
    `Important: Include ALL agents (both from previous audit and new responses) in your agent_evaluations.\n\n`;
  preparedSystemMessage = incrementalPrefix + preparedSystemMessage;
}

return {
  json: {
    ...transcriptData,
    shift_context: shiftContextSummary,
    enriched_agent_checks: enrichedChecks,
    clean_transcript_json_safe: transcriptData.clean_transcript,
    prepared_system_message: preparedSystemMessage,
    audit_type: auditType,
    is_incremental: isIncremental
  }
};

