{
  "type": "object",
  "properties": {
    "audit_summary": {
      "type": "object",
      "properties": {
        "ticket_id": { "type": "string" },
        "overall_sentiment": { "type": "string", "enum": ["Positive", "Mixed", "Negative"] },
        "overall_score": { "type": "integer", "description": "Score between -200 and +100" },
        "executive_summary": { "type": "string", "description": "High-level overview of the interaction." }
      },
      "required": ["ticket_id", "overall_sentiment", "overall_score", "executive_summary"]
    },
    "agent_evaluations": {
      "type": "array",
      "description": "MANDATORY: Per-agent evaluation with separate timing, resolution, and communication scores",
      "items": {
        "type": "object",
        "properties": {
          "agent_email": { "type": "string" },
          "agent_name": { "type": "string" },
          "timing_score": { "type": "integer", "description": "Can be negative based on response delays" },
          "resolution_score": { "type": "integer", "description": "Score INDEPENDENTLY of communication. Add +30 if resolved, +20 if actionable solution, +10 per additional issue, +10 resources, +10 escalated, +10 follow-up. Even rude agents get full credit if they solved the problem." },
          "communication_score": { "type": "integer", "minimum": -60, "maximum": 30, "description": "Strict checklist sum ONLY: +10(professional) +5(empathy) +10(resources) +5(praised) -10(unclear) -25(rude, PER INSTANCE). Example: 2 rude msgs = 10+5+5-10-25-25=-40. Range -60 to +30." },
          "overall_agent_score": { "type": "integer", "description": "Sum of timing + resolution + communication" },
          "contribution_percentage": { "type": "integer" },
          "reply_count": { "type": "integer" },
          "shift_compliance": {
            "type": "object",
            "properties": {
              "on_shift_responses": { "type": "integer" },
              "off_shift_responses": { "type": "integer" },
              "delays_while_on_shift": { "type": "integer" },
              "delays_while_off_shift": { "type": "integer" }
            }
          },
          "response_breakdown": {
            "type": "array",
            "items": {
              "type": "object",
              "properties": {
                "response_number": { "type": "integer" },
                "timestamp": { "type": "string" },
                "time_since_previous": { "type": "string" },
                "was_on_shift": { "type": "boolean" },
                "quality_score": { "type": "integer", "enum": [5, 0, -5], "description": "Must be exactly 5 (helpful), 0 (neutral), or -5 (unhelpful)" },
                "moved_toward_resolution": { "type": "boolean" },
                "brief_note": { "type": "string" }
              }
            }
          },
          "key_achievements": { "type": "array", "items": { "type": "string" } },
          "areas_for_improvement": { "type": "array", "items": { "type": "string" } },
          "reasoning": { "type": "string" }
        },
        "required": ["agent_email", "agent_name", "timing_score", "resolution_score", "communication_score", "overall_agent_score"]
      }
    },
    "agent_contributions": {
      "type": "array",
      "description": "Legacy format for backward compatibility",
      "items": {
        "type": "object",
        "properties": {
          "agent_email": { "type": "string" },
          "percentage": { "type": "integer" },
          "reply_count": { "type": "integer" },
          "score": { "type": "integer" }
        }
      }
    },
    "problem_contexts": {
      "type": "array",
      "items": {
        "type": "object",
        "properties": {
          "issue_description": { "type": "string" },
          "category": { "type": "string", "enum": ["HR Violation", "Ticket Gaming / Metric Manipulation", "Technical Inaccuracy", "Process Failure", "Policy Violation"], "description": "AGENT performance issues ONLY. HR Violation=abusive language by agent. Ticket Gaming=artificial metric inflation. Technical Inaccuracy=agent gave wrong info. Process Failure=agent failed to follow required processes (NOT the customer's reason for opening the ticket). Policy Violation=agent violated company policy. If agent handled everything correctly, return EMPTY problem_contexts array." },
          "severity": { "type": "string", "enum": ["Low", "Medium", "High", "Critical"] },
          "handling_agents": {
            "type": "array",
            "items": {
              "type": "object",
              "properties": {
                "agent_id": { "type": "string" },
                "marking": { "type": "integer", "description": "Negative points, e.g., -10" },
                "reasoning": { "type": "string" }
              }
            }
          }
        },
        "required": ["issue_description", "category", "severity", "handling_agents"]
      }
    },
    "ops_strategic": {
      "type": "object",
      "properties": {
        "doc_update_required": { "type": "boolean" },
        "faq_candidate": { "type": "boolean" },
        "problem_categories": { "type": "array", "items": { "type": "string" }, "description": "Categorize the customer issue, e.g. Billing Issue, Technical Bug, Feature Request" },
        "documentation_gaps": { "type": "array", "items": { "type": "string" }, "description": "Missing docs that could have prevented this ticket" },
        "recommended_faq": { "type": "array", "items": { "type": "string" }, "description": "Customer-facing FAQ questions this ticket suggests" }
      }
    }
  },
  "required": ["audit_summary", "agent_evaluations", "problem_contexts"]
}

parameters.jsCode:
// Check if this is single ticket mode (from Force Webhook)
// If so, don't loop back to Loop Over Items
const isSingleTicket = $node["Extract ID"].json.is_single_ticket || false;

if (isSingleTicket) {
  // Single ticket mode: don't pass data back, just finish
  return [];
} else {
  // Batch mode: pass data back to Loop Over Items
  return items;
}
